// Expandir GHL_LOCATION_IDS (CSV) en items separados para iterar
const ids = String($env.GHL_LOCATION_IDS || '').split(',').map(s => s.trim()).filter(Boolean);
if (ids.length === 0) throw new Error('GHL_LOCATION_IDS no configurado');
return ids.map(location_id => ({ json: { location_id } }));

// Llama a GHL API v2 para obtener contactos con cursor incremental.
// Respeta rate limit: 80 req/10s con backoff exponencial.
// Ref: GHL_Platform.txt seccion 5.3

const stateRow     = $input.first().json;
const location_id  = stateRow.location_id;
const lastSynced   = stateRow.last_synced_at;
const lastCursor   = stateRow.last_cursor;

const apiKey = $env.GHL_API_KEY;
if (!apiKey) throw new Error('GHL_API_KEY no configurado');

let allContacts = [];
let nextCursor  = lastCursor || null;
let page = 0;
const MAX_PAGES = 200;  // proteccion contra loop infinito

async function sleep(ms) {
  return new Promise(r => setTimeout(r, ms));
}

while (page < MAX_PAGES) {
  const url = new URL(`https://services.leadconnectorhq.com/contacts/`);
  url.searchParams.set('locationId', location_id);
  url.searchParams.set('limit', '100');
  if (lastSynced && !nextCursor) {
    url.searchParams.set('startAfterDate', lastSynced);
  }
  if (nextCursor) {
    url.searchParams.set('startAfter', nextCursor);
  }

  let resp;
  let retries = 0;
  while (retries < 5) {
    try {
      resp = await fetch(url.toString(), {
        headers: {
          'Authorization': 'Bearer ' + apiKey,
          'Version':       '2021-07-28',
          'Content-Type':  'application/json'
        }
      });
      if (resp.status === 429) {
        // Rate limit: esperar backoff exponencial
        const waitMs = Math.pow(2, retries) * 1000;
        await sleep(waitMs);
        retries++;
        continue;
      }
      break;
    } catch (err) {
      if (retries >= 4) throw err;
      await sleep(Math.pow(2, retries) * 1000);
      retries++;
    }
  }

  if (!resp.ok) throw new Error('GHL API error: ' + resp.status + ' en contacts');

  const data = await resp.json();
  const contacts = data.contacts || [];
  allContacts = allContacts.concat(contacts);

  nextCursor = data.meta?.nextPageUrl ? data.meta.startAfter : null;
  if (!nextCursor || contacts.length === 0) break;

  page++;
  // Pequena pausa para no agotar rate limit (80 req / 10s = ~125ms por req)
  await sleep(130);
}

return [{ json: { location_id, contacts: allContacts, next_cursor: nextCursor } }];

// Sanitizar todos los contactos del batch
const REGEX_GHL_ID      = /^[a-zA-Z0-9_-]{8,50}$/;
const REGEX_LOCATION_ID = /^[a-zA-Z0-9]{10,30}$/;
const REGEX_EMAIL       = /^[a-zA-Z0-9.!#$%&'*+/=?^_`{|}~-]+@[a-zA-Z0-9](?:[a-zA-Z0-9-]{0,61}[a-zA-Z0-9])?(?:\.[a-zA-Z0-9](?:[a-zA-Z0-9-]{0,61}[a-zA-Z0-9])?)*\.[a-zA-Z]{2,}$/;

function cleanStr(val, maxLen) {
  if (!val) return null;
  const s = String(val).trim().substring(0, maxLen);
  return s.length > 0 ? s : null;
}
function normalizeE164(raw) {
  if (!raw) return null;
  let digits = String(raw).replace(/[^\d+]/g, '');
  if (digits.startsWith('+')) { const c = '+' + digits.slice(1); return (c.length >= 8 && c.length <= 16) ? c : null; }
  if (/^3\d{9}$/.test(digits)) return '+57' + digits;
  if (/^57\d{10}$/.test(digits)) return '+' + digits;
  if (digits.length >= 7 && digits.length <= 15) return '+' + digits;
  return null;
}
function validateEmail(val) {
  if (!val) return null;
  const n = String(val).toLowerCase().trim().substring(0, 255);
  return REGEX_EMAIL.test(n) ? n : null;
}
function parseISODate(val) {
  if (!val) return null;
  const ts = Date.parse(String(val));
  return isNaN(ts) ? null : new Date(ts).toISOString();
}

const { location_id, contacts, next_cursor } = $input.first().json;

const cleaned = contacts
  .filter(c => {
    const cid = String(c.id || '').trim();
    const lid = String(c.locationId || '').trim();
    return REGEX_GHL_ID.test(cid) && REGEX_LOCATION_ID.test(lid);
  })
  .map(c => {
    const attrFirst = c.attributionSource || {};
    const attrLast  = c.lastAttributionSource || {};
    return {
      contact_id:          String(c.id).trim(),
      location_id:         String(c.locationId).trim(),
      email:               validateEmail(c.email),
      phone:               normalizeE164(c.phone),
      first_name:          cleanStr(c.firstName, 100),
      last_name:           cleanStr(c.lastName,  100),
      source:              cleanStr(c.source, 100),
      tags:                Array.isArray(c.tags) ? c.tags.slice(0, 200).map(t => String(t).trim().substring(0, 200)) : null,
      contact_type:        cleanStr(c.contactType || c.type, 50),
      dnd:                 c.dnd === true || c.dnd === 'true',
      custom_fields:       (c.customFields && typeof c.customFields === 'object') ? c.customFields : null,
      utm_source_first:    cleanStr(attrFirst.utmSource, 200),
      utm_medium_first:    cleanStr(attrFirst.utmMedium, 200),
      utm_campaign_first:  cleanStr(attrFirst.utmCampaign, 200),
      utm_content_first:   cleanStr(attrFirst.utmContent,  200),
      utm_term_first:      cleanStr(attrFirst.utmTerm,     200),
      landing_url_first:   cleanStr(attrFirst.url,         2048),
      referrer_first:      cleanStr(attrFirst.referrer,    2048),
      gclid_first:         cleanStr(attrFirst.gclid,       200),
      fbclid_first:        cleanStr(attrFirst.fbclid,      200),
      campaign_id_first:   cleanStr(attrFirst.campaignId,  100),
      utm_source_last:     cleanStr(attrLast.utmSource,    200),
      utm_medium_last:     cleanStr(attrLast.utmMedium,    200),
      utm_campaign_last:   cleanStr(attrLast.utmCampaign,  200),
      utm_content_last:    cleanStr(attrLast.utmContent,   200),
      landing_url_last:    cleanStr(attrLast.url,          2048),
      ghl_created_at:      parseISODate(c.dateAdded  || c.createdAt),
      ghl_updated_at:      parseISODate(c.dateUpdated || c.updatedAt),
      synced_at:           new Date().toISOString()
    };
  });

return [{ json: { location_id, contacts: cleaned, next_cursor } }];

// Para cada contacto, aplicar SCD2 via SQL parametrizado.
// Por rendimiento: primero leer todos los existentes en un solo SELECT,
// luego procesar en memoria y ejecutar las queries necesarias.
//
// NOTA: En n8n no hay acceso directo a un pg client desde Code node;
// se usan nodos Postgres subsiguientes. Este nodo prepara los datos.

const { location_id, contacts } = $input.first().json;

const TRACKED = ['email', 'phone', 'source', 'utm_source_first', 'utm_campaign_first'];
const now = new Date().toISOString();

// Preparar lista de IDs para busqueda masiva
const ids = contacts.map(c => c.contact_id);

// Pasar datos al nodo siguiente para que haga el SELECT masivo
return [{ json: { location_id, contacts, ids, tracked: TRACKED, now } }];

// Comparar incoming vs existing y generar acciones SCD2
const state = $('SCD2 Upsert Batch').first().json;
const existingRows = $input.first().json;  // filas del SELECT

const { contacts, tracked, now } = state;

// Indexar por contact_id
const existingMap = {};
const rows = Array.isArray(existingRows) ? existingRows : (existingRows.data || [existingRows]);
for (const row of rows) {
  if (row && row.contact_id) existingMap[row.contact_id] = row;
}

const inserts       = [];
const scdUpdates    = [];  // { close_surrogate, close_valid_to, record }
const minorUpdates  = [];  // { surrogate_key, synced_at, tags, custom_fields }

for (const incoming of contacts) {
  const prev = existingMap[incoming.contact_id];

  if (!prev) {
    inserts.push(Object.assign({}, incoming, { valid_from: now, valid_to: null, is_current: true, change_reason: 'initial_insert' }));
    continue;
  }

  const changedFields = tracked.filter(f => String(prev[f] ?? null) !== String(incoming[f] ?? null));

  if (changedFields.length > 0) {
    scdUpdates.push({
      close_surrogate: prev.surrogate_key,
      close_valid_to:  now,
      record: Object.assign({}, incoming, { valid_from: now, valid_to: null, is_current: true, change_reason: changedFields.map(f => f + '_change').join(', ') })
    });
  } else {
    minorUpdates.push({
      surrogate_key: prev.surrogate_key,
      synced_at:     now,
      ghl_updated_at: incoming.ghl_updated_at || now,
      tags:          incoming.tags,
      custom_fields: incoming.custom_fields
    });
  }
}

return [{ json: { inserts, scdUpdates, minorUpdates, location_id: state.location_id, next_cursor: state.next_cursor, total: contacts.length } }];

// Ejecutar SCD2 updates via Postgres nodo (limitacion: Code node no ejecuta SQL directo).
// Este nodo prepara los datos; el nodo Postgres siguiente los ejecuta.
// Por limitaciones de n8n, se procesan en el mismo nodo usando HTTP a Postgres REST si disponible,
// o se usa el patron de pasar datos al siguiente nodo Postgres.
// DECISION: pasar al nodo siguiente los scdUpdates para procesamiento.
return $input.all();
